bot.onText(/^\/fakedana(?:\s+(.+))?$/, async (msg, match) => {
  const chatId = msg.chat.id;
  const messageId = msg.message_id;
  const input = match[1];

  try {
    if (!input) {
      return bot.sendMessage(chatId, <blockquote><b>⚠️ MASUKKAN NOMINAL</b></blockquote>\n\n<b>Contoh:</b> <code>/fakedana 500.000</code>, { 
        parse_mode: "HTML",
        reply_to_message_id: messageId 
      });
    }

    // Membersihkan input agar hanya angka
    const nominalClean = input.replace(/[^0-9]/g, "");

    if (!nominalClean) {
      return bot.sendMessage(chatId, <blockquote><b>❌ NOMINAL TIDAK VALID</b></blockquote>, { 
        parse_mode: "HTML",
        reply_to_message_id: messageId 
      });
    }

    const formatted = Number(nominalClean).toLocaleString("id-ID");

    await bot.sendMessage(chatId, <blockquote><b>💸 SEDANG MEMPROSES...</b></blockquote>\n<i>Mohon tunggu, sedang membuat tampilan bukti dana.</i>, { 
      parse_mode: "HTML",
      reply_to_message_id: messageId 
    });

    const url = https://api.zenzxz.my.id/maker/fakedanav2?nominal=${encodeURIComponent(formatted)};
    const res = await axios.get(url, { responseType: "arraybuffer" });

    await bot.sendPhoto(chatId, Buffer.from(res.data), {
      caption: <blockquote><b>💰 FAKE DANA BERHASIL</b></blockquote>\n\n<b>Nominal:</b> <code>Rp${formatted}</code>\n<b>Status:</b> Sukses Dibuat,
      parse_mode: "HTML",
      reply_to_message_id: messageId
    });

  } catch (err) {
    console.error(err);
    bot.sendMessage(chatId, <blockquote><b>❌ TERJADI KESALAHAN</b></blockquote>\n<code>${err.message}</code>, { 
      parse_mode: "HTML",
      reply_to_message_id: messageId 
    });
  }
});
